    left = pd.DataFrame(
        {
            "a": [1, 5, 10],
            "b": ["x", "y", "z"],
            "left_val": ["a", "b", "c"],
        }
    )
    right = pd.DataFrame(
        {
            "a": [1, 2, 3, 6, 7],
            "b": ["x", "x", "x", "y", "z"],
            "right_val": [1, 2, 3, 6, 7],
        }
    )

    result = merge_asof(left, right, on="a", by="b", indicator=True)

    expected = pd.DataFrame(
        {
            "a": [1, 5, 10],
            "b": ["x", "y", "z"],
            "left_val": ["a", "b", "c"],
            "right_val": [1.0, 6.0, 7.0],
            "_merge": Categorical(
                ["both", "both", "both"],
                categories=["left_only", "right_only", "both"],
            ),
        }
    )

    tm.assert_frame_equal(result, expected)

